1	package dev.langchain4j.model.embedding.onnx;
2	
3	import static ai.onnxruntime.OnnxTensor.createTensor;
4	import static dev.langchain4j.internal.Exceptions.illegalArgument;
5	import static dev.langchain4j.internal.ValidationUtils.ensureNotNull;
6	import static java.nio.LongBuffer.wrap;
7	import static java.util.Collections.singletonMap;
8	import static java.util.stream.Collectors.toList;
9	
10	import ai.djl.huggingface.tokenizers.Encoding;
11	import ai.djl.huggingface.tokenizers.HuggingFaceTokenizer;
12	import ai.onnxruntime.OnnxTensor;
13	import ai.onnxruntime.OrtEnvironment;
14	import ai.onnxruntime.OrtException;
15	import ai.onnxruntime.OrtSession;
16	import ai.onnxruntime.OrtSession.Result;
17	import java.io.ByteArrayOutputStream;
18	import java.io.IOException;
19	import java.io.InputStream;
20	import java.nio.file.Path;
21	import java.util.*;
22	
23	public class OnnxBertBiEncoder {
24	
25	    private static final int MAX_SEQUENCE_LENGTH = 510; // 512 - 2 (special tokens [CLS] and [SEP])
26	
27	    private final OrtEnvironment environment;
28	    private final OrtSession session;
29	    private final Set<String> expectedInputs;
30	    private final HuggingFaceTokenizer tokenizer;
31	    private final PoolingMode poolingMode;
32	
33	    public OnnxBertBiEncoder(Path pathToModel, Path pathToTokenizer, PoolingMode poolingMode) {
34	        try {
35	            this.environment = OrtEnvironment.getEnvironment();
36	            this.session = environment.createSession(pathToModel.toString());
37	            this.expectedInputs = session.getInputNames();
38	            this.tokenizer = HuggingFaceTokenizer.newInstance(pathToTokenizer, singletonMap("padding", "false"));
39	            this.poolingMode = ensureNotNull(poolingMode, "poolingMode");
40	        } catch (Exception e) {
41	            throw new RuntimeException(e);
42	        }
43	    }
44	
45	    public OnnxBertBiEncoder(InputStream model, InputStream tokenizer, PoolingMode poolingMode) {
46	        try {
47	            this.environment = OrtEnvironment.getEnvironment();
48	            this.session = environment.createSession(loadModel(model));
49	            this.expectedInputs = session.getInputNames();
50	            this.tokenizer = HuggingFaceTokenizer.newInstance(tokenizer, singletonMap("padding", "false"));
51	            this.poolingMode = ensureNotNull(poolingMode, "poolingMode");
52	        } catch (Exception e) {
53	            throw new RuntimeException(e);
54	        }
55	    }
56	
57	    public OnnxBertBiEncoder(
58	            OrtEnvironment environment, OrtSession session, InputStream tokenizer, PoolingMode poolingMode) {
59	        try {
60	            this.environment = environment;
61	            this.session = session;
62	            this.expectedInputs = session.getInputNames();
63	            this.tokenizer = HuggingFaceTokenizer.newInstance(tokenizer, singletonMap("padding", "false"));
64	            this.poolingMode = ensureNotNull(poolingMode, "poolingMode");
65	        } catch (Exception e) {
66	            throw new RuntimeException(e);
67	        }
68	    }
69	
70	    static class EmbeddingAndTokenCount {
71	
72	        float[] embedding;
73	        int tokenCount;
74	
75	        EmbeddingAndTokenCount(float[] embedding, int tokenCount) {
76	            this.embedding = embedding;
77	            this.tokenCount = tokenCount;
78	        }
79	    }
80	
81	    EmbeddingAndTokenCount embed(String text) {
82	
83	        List<String> tokens = tokenizer.tokenize(text);
84	        List<List<String>> partitions = partition(tokens, MAX_SEQUENCE_LENGTH);
85	
86	        if (partitions.isEmpty()) {
87	            throw illegalArgument("Cannot embed empty or whitespace-only text");
88	        }
89	
90	        List<float[]> embeddings = new ArrayList<>();
91	        for (List<String> partition : partitions) {
92	            try (Result result = encode(partition)) {
93	                float[] embedding = toEmbedding(result);
94	                embeddings.add(embedding);
95	            } catch (OrtException e) {
96	                throw new RuntimeException(e);
97	            }
98	        }
99	
100	        List<Integer> weights = partitions.stream().map(List::size).collect(toList());
101	
102	        float[] embedding = normalize(weightedAverage(embeddings, weights));
103	
104	        return new EmbeddingAndTokenCount(embedding, tokens.size());
105	    }
106	
107	    static List<List<String>> partition(List<String> tokens, int partitionSize) {
108	        List<List<String>> partitions = new ArrayList<>();
109	        int from = 1; // Skip the first (CLS) token
110	
111	        while (from < tokens.size() - 1) { // Skip the last (SEP) token
112	            int to = from + partitionSize;
113	
114	            if (to >= tokens.size() - 1) {
115	                to = tokens.size() - 1;
116	            } else {
117	                // ensure we don't split word across partitions
118	                while (tokens.get(to).startsWith("##")) {
119	                    to--;
120	                }
121	            }
122	
123	            partitions.add(tokens.subList(from, to));
124	
125	            from = to;
126	        }
127	
128	        return partitions;
129	    }
130	
131	    private Result encode(List<String> tokens) throws OrtException {
132	
133	        Encoding encoding = tokenizer.encode(toText(tokens), true, false);
134	
135	        long[] inputIds = encoding.getIds();
136	        long[] attentionMask = encoding.getAttentionMask();
137	        long[] tokenTypeIds = encoding.getTypeIds();
138	
139	        long[] shape = {1, inputIds.length};
140	
141	        try (OnnxTensor inputIdsTensor = createTensor(environment, wrap(inputIds), shape);
142	                OnnxTensor attentionMaskTensor = createTensor(environment, wrap(attentionMask), shape);
143	                OnnxTensor tokenTypeIdsTensor = createTensor(environment, wrap(tokenTypeIds), shape)) {
144	            Map<String, OnnxTensor> inputs = new HashMap<>();
145	            inputs.put("input_ids", inputIdsTensor);
146	            inputs.put("attention_mask", attentionMaskTensor);
147	
148	            if (expectedInputs.contains("token_type_ids")) {
149	                inputs.put("token_type_ids", tokenTypeIdsTensor);
150	            }
151	
152	            return session.run(inputs);
153	        }
154	    }
155	
156	    private String toText(List<String> tokens) {
157	
158	        String text = tokenizer.buildSentence(tokens);
159	
160	        List<String> tokenized = tokenizer.tokenize(text);
161	        List<String> tokenizedWithoutSpecialTokens = new LinkedList<>(tokenized);
162	        tokenizedWithoutSpecialTokens.remove(0);
163	        tokenizedWithoutSpecialTokens.remove(tokenizedWithoutSpecialTokens.size() - 1);
164	
165	        if (tokenizedWithoutSpecialTokens.equals(tokens)) {
166	            return text;
167	        } else {
168	            return String.join("", tokens);
169	        }
170	    }
171	
172	    private float[] toEmbedding(Result result) throws OrtException {
173	        float[][] vectors = ((float[][][]) result.get(0).getValue())[0];
174	        return pool(vectors);
175	    }
176	
177	    private float[] pool(float[][] vectors) {
178	        switch (poolingMode) {
179	            case CLS:
180	                return clsPool(vectors);
181	            case MEAN:
182	                return meanPool(vectors);
183	            default:
184	                throw illegalArgument("Unknown pooling mode: " + poolingMode);
185	        }
186	    }
187	
188	    private static float[] clsPool(float[][] vectors) {
189	        return vectors[0];
190	    }
191	
192	    private static float[] meanPool(float[][] vectors) {
193	
194	        int numVectors = vectors.length;
195	        int vectorLength = vectors[0].length;
196	
197	        float[] averagedVector = new float[vectorLength];
198	
199	        for (float[] vector : vectors) {
200	            for (int j = 0; j < vectorLength; j++) {
201	                averagedVector[j] += vector[j];
202	            }
203	        }
204	
205	        for (int j = 0; j < vectorLength; j++) {
206	            averagedVector[j] /= numVectors;
207	        }
208	
209	        return averagedVector;
210	    }
211	
212	    private float[] weightedAverage(List<float[]> embeddings, List<Integer> weights) {
213	        if (embeddings.size() == 1) {
214	            return embeddings.get(0);
215	        }
216	
217	        int dimensions = embeddings.get(0).length;
218	
219	        float[] averagedEmbedding = new float[dimensions];
220	        int totalWeight = 0;
221	
222	        for (int i = 0; i < embeddings.size(); i++) {
223	            int weight = weights.get(i);
224	            totalWeight += weight;
225	
226	            for (int j = 0; j < dimensions; j++) {
227	                averagedEmbedding[j] += embeddings.get(i)[j] * weight;
228	            }
229	        }
230	
231	        for (int j = 0; j < dimensions; j++) {
232	            averagedEmbedding[j] /= totalWeight;
233	        }
234	
235	        return averagedEmbedding;
236	    }
237	
238	    private static float[] normalize(float[] vector) {
239	
240	        float sumSquare = 0;
241	        for (float v : vector) {
242	            sumSquare += v * v;
243	        }
244	        float norm = (float) Math.sqrt(sumSquare);
245	
246	        float[] normalizedVector = new float[vector.length];
247	        for (int i = 0; i < vector.length; i++) {
248	            normalizedVector[i] = vector[i] / norm;
249	        }
250	
251	        return normalizedVector;
252	    }
253	
254	    int countTokens(String text) {
255	        return tokenizer.tokenize(text).size();
256	    }
