package dev.langchain4j.model.scoring.onnx;

import ai.onnxruntime.OrtSession;
import org.junit.jupiter.api.Test;
import sun.misc.Unsafe;

import java.lang.reflect.Field;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.verify;

class OnnxScoringModelCloseTest {

    @Test
    void should_implement_auto_closeable() {
        assertThat(OnnxScoringModel.class).isAssignableTo(AutoCloseable.class);
    }

    @Test
    void should_close_ort_session() throws Exception {
        OrtSession session = mock(OrtSession.class);
        OnnxScoringBertCrossEncoder crossEncoder = allocate(OnnxScoringBertCrossEncoder.class);
        setField(crossEncoder, "session", session);

        OnnxScoringModel model = allocate(OnnxScoringModel.class);
        setField(model, "onnxBertBiEncoder", crossEncoder);

        model.close();

        verify(session).close();
    }

    private static <T> T allocate(Class<T> clazz) throws InstantiationException, NoSuchFieldException, IllegalAccessException {
        Field unsafeField = Unsafe.class.getDeclaredField("theUnsafe");
        unsafeField.setAccessible(true);
        return clazz.cast(((Unsafe) unsafeField.get(null)).allocateInstance(clazz));
    }

    private static void setField(Object target, String fieldName, Object value) throws NoSuchFieldException, IllegalAccessException {
        Field field = target.getClass().getDeclaredField(fieldName);
        field.setAccessible(true);
        field.set(target, value);
    }
}

